#include <cmath>

class Vector {
public:
    double x, y;
    Vector(double x, double y) : x(x), y(y) {}
    double magnitude() const {
        return std::sqrt(x * x + y * y);
    }
};

#include <vector>
#include <algorithm>

std::vector<int> getPositives(const std::vector<int>& nums) {
    std::vector<int> result;
    std::copy_if(nums.begin(), nums.end(), std::back_inserter(result), [](int n) {
        return n > 0;
    });
    return result;
}
